Fie blocul PLSQL de mai jos. Tabelele exista, au coloanele referite si cel putin 10 randuri fiecare. Unele departamente au angajati, altele nu.

DECLARE
  cursor c is SELECT DENUMIRE_DEP, COUNT(ID_ANGAJAT) NR_ANG
  FROM ANGAJATI A RIGHT JOIN DEPARTAMENTE D ON A.ID_DEPARTAMENT=D.ID_DEPARTAMENT
  GROUP BY DENUMIRE_DEP
  ORDER BY COUNT(ID_ANGAJAT) DESC;
  r c%rowtype;
BEGIN
  open c;
  DBMS_OUTPUT.PUT_LINE('Numar de elemente '||c%rowcount);
  LOOP
    fetch c into r;
    exit when c%notfound;
    IF r.NR_ANG=1 THEN
      DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' ARE UN ANGAJAT');
    ELSIF r.NR_ANG=0 THEN
      DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' NU ARE ANGAJATI');
    ELSE
      DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' ARE '|| r.NR_ANG||' ANGAJATI');
    END IF;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Numar de elemente '||c%rowcount);
  close c;
  open c;
  fetch c into r;
  fetch c into r;
  DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' ARE '|| r.NR_ANG||' ANGAJATI');
END;
/

